            time_penalty = float('inf')  # Infeasible

        if time_penalty < min_time_penalty:
            min_time_penalty = time_penalty
            best_node = idx

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(coord1, coord2, speed):
        return np.linalg.norm(coord1 - coord2) / speed

    best_node = None
    min_score = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_t = travel_time(cur_truck_pos, customer, truck_speed)
        arrival_time = current_time + travel_t
        window_start, window_end = time_windows[i]

        if arrival_time < window_start:
            wait_penalty = window_start - arrival_time
        else:
            wait_penalty = 0

        urgency = max(0, window_end - current_time)  # lesser value means more urgent
        score = travel_t + wait_penalty * 2 + urgency  # larger waiting penalties, and consider urgency in the score

        if score < min_score:
            min_score = score
            best_node = i

    return best_node
